sub extract_pdf_data {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $page_count = $pdf->pages;
    my @data = [];

    for (my $page = 1; $page <= $page_count; $page++) {
        my $page_obj = $pdf->page($page);
        my $text = $page_obj->text;

        # Example: Extract the first line of text (you can modify this to extract specific information)
