sub save_to_csv {
    my ($data, $filename) = @_;
    my $csv = Text::CSV_XS->new({ binary => 1, auto_diag => 1 });

    open my $fh, '>', $filename or die "Cannot open file: $!";
    $csv->print($fh, $_) for @$data;
